// ============================================================================
// FORMAT SPEAKER TRANSCRIPT
// Turns Gladia's diarized utterances into a clean, readable Markdown transcript.
// Consecutive lines from the same speaker are grouped into one block, the
// zero-based speaker index (0, 1, 2...) is relabeled to Speaker 1 / 2 / 3, and
// each block is stamped with its start time as [mm:ss]. If no utterances came
// back, it falls back to the plain full_transcript so nothing is lost. The
// finished Markdown is attached as a binary file for the Drive upload.
// ============================================================================

const result = $json.result || {};
const transcription = result.transcription || {};
const utterances = Array.isArray(transcription.utterances) ? transcription.utterances : [];

const mediaUrl = $('Receive Recording Request').first().json['Media URL'] || '';

// Seconds -> mm:ss (or hh:mm:ss past an hour).
function stamp(sec) {
  const total = Math.max(0, Math.floor(Number(sec) || 0));
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const pad = (n) => String(n).padStart(2, '0');
  return h > 0 ? h + ':' + pad(m) + ':' + pad(s) : pad(m) + ':' + pad(s);
}

// Group consecutive utterances that share a speaker into one spoken block.
const blocks = [];
let current = null;
for (const u of utterances) {
  const speaker = Number.isFinite(Number(u.speaker)) ? Number(u.speaker) : 0;
  const text = String(u.text || '').trim();
  if (!text) continue;
  if (!current || current.speaker !== speaker) {
    current = { speaker, start: u.start, parts: [text] };
    blocks.push(current);
  } else {
    current.parts.push(text);
  }
}

const speakerCount = new Set(blocks.map((b) => b.speaker)).size;

let bodyLines;
if (blocks.length) {
  // Relabel 0 -> Speaker 1, and stamp each block with its start time.
  bodyLines = blocks.map(
    (b) => 'Speaker ' + (b.speaker + 1) + ' [' + stamp(b.start) + ']: ' + b.parts.join(' ')
  );
} else {
  bodyLines = [String(transcription.full_transcript || 'No transcript was returned.')];
}

const header = [
  '# Speaker-labeled transcript',
  '',
  '- Source: ' + (mediaUrl || 'unknown'),
  '- Speakers detected: ' + (speakerCount || 'n/a'),
  '- Transcribed with Gladia diarization',
  '',
  '---',
  '',
].join('\n');

const transcriptMd = header + bodyLines.join('\n\n') + '\n';

// Deterministic, filesystem-safe file name derived from the media URL.
const rawName = (mediaUrl.split('/').pop() || 'recording').split('?')[0].replace(/\.[^.]+$/, '');
const slug =
  rawName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40) || 'recording';
const day = new Date().toISOString().slice(0, 10);
const filename = 'transcript-' + slug + '-' + day + '.md';

const binary = await this.helpers.prepareBinaryData(Buffer.from(transcriptMd, 'utf8'), filename, 'text/markdown');

return [
  {
    json: {
      filename,
      speaker_count: speakerCount,
      media_url: mediaUrl,
      character_count: transcriptMd.length,
    },
    binary: { data: binary },
  },
];

